import{_ as e,o as n,c as t,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"React Native Advanced Features","description":"","frontmatter":{"title":"React Native Advanced Features","slug":"react-native-advanced-features"},"headers":[],"relativePath":"developer-hub/react-native-advanced-features.md","filePath":"developer-hub/react-native-advanced-features.md"}'),i={name:"developer-hub/react-native-advanced-features.md"};function o(r,a,l,p,c,h){return n(),t("div",null,[...a[0]||(a[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch React Native SDK exposes a set of methods specifically made for React Native apps, which you can call using JavaScript.</p><p>If you need to access a feature that lives in the Branch iOS SDK or Branch Android SDK, you can call those native SDKs directly in the relevant language.</p><p><a href="./ios-full-reference.html">iOS SDK Full Reference</a></p><p><a href="./android-full-reference.html">Android SDK Full Reference</a></p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you implement the features on this page, you first need to:</p><ol><li><p>Create a <a href="https://dashboard.branch.io/?_gl=1*4u8xew*_ga*MTE0ODc2MjU5OC4xNjc5MzM4OTI0*_ga_KSDD8Y11CT*MTcxMzg4NzAyMC41MjQuMS4xNzEzODk5MTUzLjU5LjAuMA.." target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p><a href="./react-native-basic-integration.html">Integrate</a> the Branch React Native SDK into your mobile app.</p></li><li><p><a href="./react-native-basic-integration.html#5-validate-integration">Validate</a> your integration.</p></li><li><p>Import Branch by adding the following import statement to any React Native source file that uses the SDK:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import branch from &#39;react-native-branch&#39;</span></span></code></pre></div></li></ol><h2 id="defer-initialization-for-plugin-runtime" tabindex="-1">Defer Initialization for Plugin Runtime <a class="header-anchor" href="#defer-initialization-for-plugin-runtime" aria-label="Permalink to &quot;Defer Initialization for Plugin Runtime&quot;">​</a></h2><p>It&#39;s possible you might run into race conditions which cause your app to not receive Branch params on cold starts.</p><p>If this happens, you may need to defer loading the native iOS or Android layer.</p><p>To do this, add the following code to your <code>branch.json</code> <a href="./react-native-basic-integration.html#3-configure-app">file</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;deferInitForPluginRuntime&quot;: true</span></span>
<span class="line"><span>}</span></span></code></pre></div><h4 id="set-initialization-metadata" tabindex="-1">Set Initialization Metadata <a class="header-anchor" href="#set-initialization-metadata" aria-label="Permalink to &quot;Set Initialization Metadata&quot;">​</a></h4><p>Some third-party <a href="./data-integration-partners.html">Data Integration Partners</a> require setting certain identifiers before initializing Branch.</p><p>To do this:</p><ol><li>Make sure you have added <code>deferInitForPluginRuntime</code> to your <code>branch.json</code> file as shown <a href="./react-native-advanced-features.html#defer-initialization-for-plugin-runtime">above</a>.</li><li>Use the <code>setRequestMetadata()</code> method to set your identifiers:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import branch from &#39;react-native-branch&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Call \`setRequestMetadata\` before \`subscribe\`</span></span>
<span class="line"><span>branch.setRequestMetadata(&#39;$analytics_visitor_id&#39;, &#39;000001&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.subscribe(({error, params}) =&gt; {</span></span>
<span class="line"><span>  // ...</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>See our <a href="./ios-advanced-features.html#set-initialization-metadata">iOS</a> and <a href="./android-advanced-features.html#set-initialization-metadata">Android</a> documentation for more.</p><h2 id="set-branch-api-url" tabindex="-1">Set Branch API URL <a class="header-anchor" href="#set-branch-api-url" aria-label="Permalink to &quot;Set Branch API URL&quot;">​</a></h2><p>It is possible to set a custom base URL for all calls to the Branch API.</p><p>To do this, add the following code to your <code>branch.json</code> <a href="./react-native-basic-integration.html#3-configure-app">file</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;apiUrl&quot;: &quot;https://protected-api.branch.io&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="nativelinktm-deferred-deep-linking" tabindex="-1">NativeLink™ Deferred Deep Linking <a class="header-anchor" href="#nativelinktm-deferred-deep-linking" aria-label="Permalink to &quot;NativeLink™ Deferred Deep Linking&quot;">​</a></h2><p>Use iOS pasteboard to enable deferred deep linking via Branch NativeLink™, which enables 100% matching on iOS through Installs.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisite</p><p>Minimum SDK Version: v5.0.4</p><p>To use this feature you must:</p><ul><li><a href="./configure-default-link-behaviors.html#3-ios-default-link-behavior">Enable NativeLink™ Deep Linking</a> in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Branch Dashboard App Settings tab</a></li></ul><p><strong>or</strong></p><ul><li>Manually configure your Branch Link to use <a href="./creating-a-deep-link.html#deep-linking">$ios_nativelink</a></li></ul></div><p>Please note that deferred deep linking is part of our Engagement package. Learn more on our <a href="./packaging.html">pricing</a> page.</p><h4 id="implementation-options" tabindex="-1">Implementation Options <a class="header-anchor" href="#implementation-options" aria-label="Permalink to &quot;Implementation Options&quot;">​</a></h4><h5 id="basic-example" tabindex="-1">Basic Example <a class="header-anchor" href="#basic-example" aria-label="Permalink to &quot;Basic Example&quot;">​</a></h5><p>To enable this feature, call the <code>RNBranch.branch checkPasteboardOnInstall</code> method in the AppDelegate file. Call this method prior to Branch initialization.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- (BOOL)application:(UIApplication *)application didFinishLaunchingWithOptions:(NSDictionary *)launchOptions {</span></span>
<span class="line"><span>	[RNBranch.branch checkPasteboardOnInstall]; </span></span>
<span class="line"><span>	[RNBranch initSessionWithLaunchOptions:launchOptions isReferrable:YES];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	return YES;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h5 id="example-with-ios-15-x-check" tabindex="-1">Example With iOS 15.X Check <a class="header-anchor" href="#example-with-ios-15-x-check" aria-label="Permalink to &quot;Example With iOS 15.X Check&quot;">​</a></h5><p>If you only want to enable this feature on iOS 15.X, include an iOS version check prior to calling the <code>RNBranch.branch checkPasteboardOnInstall</code> method. Both the version check and the method call happen inside the AppDelegate file, before Branch initialization.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- (BOOL)application:(UIApplication *)application didFinishLaunchingWithOptions:(NSDictionary *)launchOptions {</span></span>
<span class="line"><span>    if ([[[UIDevice currentDevice] systemVersion] compare:@&quot;15.0&quot; options:NSNumericSearch] != NSOrderedAscending)</span></span>
<span class="line"><span>        [RNBranch.branch checkPasteboardOnInstall]; </span></span>
<span class="line"><span></span></span>
<span class="line"><span>    [RNBranch initSessionWithLaunchOptions:launchOptions isReferrable:YES];</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    return YES;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h5 id="example-with-pasteboard-visibility-check" tabindex="-1">Example With Pasteboard Visibility Check <a class="header-anchor" href="#example-with-pasteboard-visibility-check" aria-label="Permalink to &quot;Example With Pasteboard Visibility Check&quot;">​</a></h5><p>You can also check whether the pasteboard toast will show or not by using the <code>RNBranch.branch willShowPasteboardToast</code> method. This call happens inside the AppDelegate file, before Branch initialization.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- (BOOL)application:(UIApplication *)application didFinishLaunchingWithOptions:(NSDictionary *)launchOptions {</span></span>
<span class="line"><span>    [RNBranch.branch checkPasteboardOnInstall];</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>    if ([RNBranch.branch willShowPasteboardToast]) {</span></span>
<span class="line"><span>    // ...</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    [RNBranch initSessionWithLaunchOptions:launchOptions isReferrable:YES];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    return YES;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="event-tracking" tabindex="-1">Event Tracking <a class="header-anchor" href="#event-tracking" aria-label="Permalink to &quot;Event Tracking&quot;">​</a></h2><p>By default, the Branch React Native SDK tracks clicks, opens, installs, reinstalls and impressions automatically (out-of-the-box).</p><p>You can also use the <code>BranchEvent</code> class to <a href="./track-branch-events.html">track special user actions or application-specific events</a>. For example, you can track when a user adds an item to a shopping cart or searches for a keyword.</p><p>In short, a <code>BranchEvent</code> instance corresponds to an in-app event that you want to log with Branch.</p><p>You can use a <code>BranchUniversalObject</code> (BUO) instance to populate the <code>contentItems</code> field of the <code>BranchEvent</code>. This is how you associate BUO data with a specific event.</p><p>Learn more about <a href="./track-branch-events.html">tracking events</a> and the <code>logEvent()</code> <a href="./react-native-full-reference.html#logevent">method</a> in our respective guides.</p><h2 id="push-notifications" tabindex="-1">Push Notifications <a class="header-anchor" href="#push-notifications" aria-label="Permalink to &quot;Push Notifications&quot;">​</a></h2><p>To track Branch Deep Links in your push notifications, use the Branch React Native SDK <code>openURL()</code> method:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import branch from &#39;react-native-branch&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let data = {</span></span>
<span class="line"><span>  &quot;aps&quot;: {</span></span>
<span class="line"><span>    &quot;alert&quot;: &quot;Push notification with a Branch deep link&quot;,</span></span>
<span class="line"><span>    &quot;badge&quot;: &quot;1&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;branch&quot;: &quot;https://example.app.link/u3fzDwyyjF&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.openURL(data[&quot;branch&quot;],{newActivity: true})</span></span></code></pre></div><p>The JSON object you pass to <code>openURL()</code> can take any form, but it must include a field called <code>&quot;branch&quot;</code> at the top level, which points to a Branch Link.</p><p>Add this method to the callback function of the push notification handler (<a href="./ios-advanced-features.html#push-notifications">iOS</a> and <a href="./android-advanced-features.html#push-notifications">Android</a>).</p><h2 id="user-data" tabindex="-1">User Data <a class="header-anchor" href="#user-data" aria-label="Permalink to &quot;User Data&quot;">​</a></h2><h4 id="google-dma-compliance" tabindex="-1">Google DMA Compliance <a class="header-anchor" href="#google-dma-compliance" aria-label="Permalink to &quot;Google DMA Compliance&quot;">​</a></h4><p>In response to the European Union&#39;s enactment of the Digital Markets Act (DMA), the Branch React Native SDK includes the <code>setDMAParamsForEEA()</code> method to help you pass consent information from your user to Google.</p><p>The setDMAParamsForEEA() method takes 3 parameters:</p><table tabindex="0"><thead><tr><th>Parameter Name</th><th>Type</th><th>Description</th><th>When <code>true</code></th><th>When <code>false</code></th></tr></thead><tbody><tr><td><code>eeaRegion</code></td><td>Boolean</td><td>Whether European regulations, including the DMA, apply to this user and conversion.</td><td>User is <strong>included</strong> in European Union regulations. For example, if the user is located within the EEA, they are within the scope of DMA.</td><td>User is considered <strong>excluded</strong> from European Union regulations.</td></tr><tr><td><code>adPersonalizationConsent</code></td><td>Boolean</td><td>Whether end user has granted or denied ads personalization consent.</td><td>User has <strong>granted</strong> consent for ads personalization.</td><td>User has <strong>denied</strong> consent for ads personalization.</td></tr><tr><td><code>adUserDataUsageConsent</code></td><td>Boolean</td><td>Whether end user has granted or denied consent for 3P transmission of user level data for ads.</td><td>User has <strong>granted</strong> consent for 3P transmission of user-level data for ads.</td><td>User has <strong>denied</strong> consent for 3P transmission of user-level data for ads.</td></tr></tbody></table><h5 id="default-behavior" tabindex="-1">Default Behavior <a class="header-anchor" href="#default-behavior" aria-label="Permalink to &quot;Default Behavior&quot;">​</a></h5><p>When parameters are successfully set using <code>setDMAParamsForEEA()</code>, they will be sent along with every future request to the following Branch endpoints:</p><ul><li><code>/v1/install</code></li><li><code>/v1/open</code></li><li><code>/v2/event</code></li></ul><div class="warning custom-block"><p class="custom-block-title">Omitted by Default</p><p>Please note that the 3 consent parameters related to <code>setDMAParamsForEEA()</code> are all omitted by default.</p><p><strong>Failure to include user consent signals may result in attribution or campaign performance degradation. For additional information, please reach out to your Google AM.</strong></p><p>Making a successful <code>setDMAParamsForEEA()</code> call requires that all 3 parameters be set.</p></div>`,57)])])}const b=e(i,[["render",o]]);export{u as __pageData,b as default};
